using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Build the IChatClient ──────────────────────────────────────────────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

// ── Tools ──────────────────────────────────────────────────────────────────────
var researchTools = new ResearchTools();
var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// ── Agent ──────────────────────────────────────────────────────────────────────
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user
    gives you and produce a well-structured summary.

    Workflow:
    1. Break the topic into 2-4 sub-queries that cover different angles.
    2. Use the SearchWeb tool to find information for each sub-query.
    3. Use the SaveNote tool to record key facts and source URLs as you go.
    4. After researching, use GetNotes to review everything you collected.
    5. Produce a final markdown summary that includes:
       - An overview paragraph
       - Key findings as bullet points
       - A "Sources" section listing the URLs you found

    Be thorough but concise. Always cite sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking tools",
    tools: tools);

// ── Interactive Loop ───────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════════════════╗");
Console.WriteLine("║          🔍  AI Research Agent                  ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to exit.  ║");
Console.WriteLine("╚══════════════════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input))
        continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    researchTools.ClearNotes();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)\n");
    Console.ResetColor();

    try
    {
        var response = await agent.RunAsync(input, session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("── Research Summary ─────────────────────────────────────");
        Console.ResetColor();

        foreach (var message in response.Messages)
        {
            if (message.Role == ChatRole.Assistant)
                Console.WriteLine(message.Text);
        }

        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

// ── Tool Implementations ───────────────────────────────────────────────────────
public sealed class ResearchTools
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" }
        },
        Timeout = TimeSpan.FromSeconds(15)
    };

    private readonly List<string> _notes = [];

    [Description("Search the web for a query and return a list of result titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important facts, quotes, or source URLs you find.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        Console.ResetColor();

        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");

        return sb.ToString();
    }

    public void ClearNotes() => _notes.Clear();

    private static string ParseSearchResults(string html)
    {
        var sb = new StringBuilder();
        var resultCount = 0;

        // Extract result blocks from DuckDuckGo HTML search results
        var resultPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        foreach (Match match in resultPattern.Matches(html))
        {
            if (resultCount >= 8)
                break;

            var rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value);
            var title = StripHtml(match.Groups["title"].Value);
            var snippet = StripHtml(match.Groups["snippet"].Value);

            // DuckDuckGo wraps URLs in a redirect; extract the real URL
            var actualUrl = ExtractRedirectUrl(rawUrl);

            sb.AppendLine($"Title: {title}");
            sb.AppendLine($"URL: {actualUrl}");
            sb.AppendLine($"Snippet: {snippet}");
            sb.AppendLine();
            resultCount++;
        }

        return resultCount > 0
            ? sb.ToString()
            : "No results found for this query.";
    }

    private static string StripHtml(string html) =>
        WebUtility.HtmlDecode(Regex.Replace(html, @"<[^>]+>", "")).Trim();

    private static string ExtractRedirectUrl(string url)
    {
        // DuckDuckGo URLs look like: //duckduckgo.com/l/?uddg=<encoded_url>&...
        var match = Regex.Match(url, @"uddg=(?<real>[^&]+)");
        return match.Success
            ? WebUtility.UrlDecode(match.Groups["real"].Value)
            : url;
    }
}

