 using System.Text;
 using System.Text.RegularExpressions;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // ── Configuration ──────────────────────────────────────────────────────────────
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

 // ── Build the IChatClient ──────────────────────────────────────────────────────
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(model)
     .AsIChatClient();

 // ── Tools ──────────────────────────────────────────────────────────────────────
 var researchTools = new ResearchTools();
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(researchTools.SearchWeb),
     AIFunctionFactory.Create(researchTools.SaveNote),
     AIFunctionFactory.Create(researchTools.GetNotes),
 };

 // ── Agent ──────────────────────────────────────────────────────────────────────
 const string instructions = """
     You are a research agent. Your job is to thoroughly research a topic the user
     gives you and produce a well-structured summary.

     Workflow:
     1. Break the topic into 2-4 sub-queries that cover different angles.
     2. Use the SearchWeb tool to find information for each sub-query.
     3. Use the SaveNote tool to record key facts and source URLs as you go.
     4. After researching, use GetNotes to review everything you collected.
     5. Produce a final markdown summary that includes:
        - An overview paragraph
        - Key findings as bullet points
        - A "Sources" section listing the URLs you found

     Be thorough but concise. Always cite sources.
     """;

 var agent = new ChatClientAgent(
     chatClient,
     instructions: instructions,
     name: "ResearchAgent",
     description: "Researches topics using web search and note-taking tools",
     tools: tools);

 // ── Interactive Loop ───────────────────────────────────────────────────────────
 Console.WriteLine("╔══════════════════════════════════════════════════╗");
