 // ── Tool Implementations ───────────────────────────────────────────────────────
 public sealed class ResearchTools
 {
     private static readonly HttpClient Http = new()
     {
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0" }
         },
         Timeout = TimeSpan.FromSeconds(15)
     };

     private readonly List<string> _notes = [];

     [Description("Search the web for a query and return a list of result titles, snippets, and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query string")] string query)
     {
         Console.ForegroundColor = ConsoleColor.Yellow;
         Console.WriteLine($"  🔎 Searching: \"{query}\"");
         Console.ResetColor();

         try
         {
             var encoded = WebUtility.UrlEncode(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";
             var html = await Http.GetStringAsync(url);
             return ParseSearchResults(html);
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     [Description("Save a research note. Use this to record important facts, quotes, or source URLs you find.")]
     public string SaveNote(
         [Description("The note text to save")] string note)
     {
         _notes.Add(note);

         Console.ForegroundColor = ConsoleColor.DarkYellow;
         Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
         Console.ResetColor();

         return $"Note saved. You now have {_notes.Count} note(s).";
     }

     [Description("Retrieve all saved research notes.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         var sb = new StringBuilder();
         for (var i = 0; i < _notes.Count; i++)
             sb.AppendLine($"[{i + 1}] {_notes[i]}");

         return sb.ToString();
     }

     public void ClearNotes() => _notes.Clear();

     private static string ParseSearchResults(string html)
     {
         var sb = new StringBuilder();
         var resultCount = 0;

         // Extract result blocks from DuckDuckGo HTML search results
         var resultPattern = new Regex(
             @"<a[^>]+class=""result__a""[^>]*href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
             RegexOptions.Singleline | RegexOptions.IgnoreCase);

         foreach (Match match in resultPattern.Matches(html))
         {
             if (resultCount >= 8)
                 break;

             var rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value);
             var title = StripHtml(match.Groups["title"].Value);
             var snippet = StripHtml(match.Groups["snippet"].Value);

             // DuckDuckGo wraps URLs in a redirect; extract the real URL
             var actualUrl = ExtractRedirectUrl(rawUrl);

             sb.AppendLine($"Title: {title}");
             sb.AppendLine($"URL: {actualUrl}");
             sb.AppendLine($"Snippet: {snippet}");
             sb.AppendLine();
             resultCount++;
         }

         return resultCount > 0
             ? sb.ToString()
             : "No results found for this query.";
     }

     private static string StripHtml(string html) =>
         WebUtility.HtmlDecode(Regex.Replace(html, @"<[^>]+>", "")).Trim();

     private static string ExtractRedirectUrl(string url)
     {
         // DuckDuckGo URLs look like: //duckduckgo.com/l/?uddg=<encoded_url>&...
         var match = Regex.Match(url, @"uddg=(?<real>[^&]+)");
         return match.Success
             ? WebUtility.UrlDecode(match.Groups["real"].Value)
             : url;
     }
 }

